package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.util.List;
import java.util.ArrayList;
import java.lang.reflect.Constructor;

class CartTest {

  @Test
  void testGetLineItems_returnsLineItemsList() throws Exception {
    List<LineItem> items = new ArrayList<>();
    items.add(new LineItem("item1", 2));
    items.add(new LineItem("item2", 5));

    // Use reflection to instantiate Cart since Cart class is not directly accessible
    Class<?> cartClass = Class.forName("com.google.gson.examples.android.model.Cart");
    Constructor<?> constructor = cartClass.getDeclaredConstructor(List.class, String.class, String.class);
    constructor.setAccessible(true);
    Object cart = constructor.newInstance(items, "buyerName", "1234-5678-9012-3456");

    // Invoke getLineItems method via reflection
    @SuppressWarnings("unchecked")
    List<LineItem> result = (List<LineItem>) cartClass.getMethod("getLineItems").invoke(cart);

    assertNotNull(result);
    assertEquals(2, result.size());

    LineItem item0 = result.get(0);
    LineItem item1 = result.get(1);

    assertEquals("item1", item0.getName());
    assertEquals(2, item0.getQuantity());
    assertEquals("item2", item1.getName());
    assertEquals(5, item1.getQuantity());
  }

  // Minimal LineItem class for testing
  static class LineItem {
    private final String name;
    private final int quantity;

    LineItem(String name, int quantity) {
      this.name = name;
      this.quantity = quantity;
    }

    String getName() {
      return name;
    }

    int getQuantity() {
      return quantity;
    }
  }
}
